import net.sf.jsqlparser.expression.Function;

import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.List;

/**
 * UrlEncodeFunction  ->  url_encode(str[, charset])
 * description:
 * - Return NULL if 'str' is NULL, or there is an issue with the encoding process(such as encountering an illegal
 *          escape pattern), or the encoding scheme is not supported;
 * - Return the result of translating 'str' into 'application/x-www-form-urlencoded' format using the specified encoding scheme.
 * - If charset is not specified, UTF-8 is used by default.
 */
@TransformFunction(type = FunctionConstant.STRING_TYPE, names = {
        "url_encode"}, parameter = "(String str[, String charset])", descriptions = {
                "- Return \"\" if 'str' is NULL, or there is an issue with the encoding process(such as encountering an "
                        +
                        "illegal escape pattern), or the encoding scheme is not supported;",
                "- Return the result of translating 'str' into 'application/x-www-form-urlencoded' format using the " +
                        "specified encoding scheme (UTF-8 by default)."
        }, examples = {
                "url_encode('https://apache.inlong.com/search?q=java url encode') = \"https%3A%2F%2Fapache.inlong.com%2Fsearch%3Fq%3Djava+url+encode\"",
                "url_encode('你好', 'UTF-8') = \"%E4%BD%A0%E5%A5%BD\""})
public class UrlEncodeFunction implements ValueParser {

    private final ValueParser stringParser;
    private final ValueParser charsetParser;

    public UrlEncodeFunction(Function expr) {
        List<Expression> expressions = expr.getParameters().getExpressions();
        stringParser = OperatorTools.buildParser(expressions.get(0));
        if (expressions.size() == 2) {
            charsetParser = OperatorTools.buildParser(expressions.get(1));
        } else {
            charsetParser = null;
        }
    }

    @Override
    public Object parse(SourceData sourceData, int rowIndex, Context context) {
        Object stringObj = stringParser.parse(sourceData, rowIndex, context);
        if (stringObj == null) {
            return null;
        }

        String string = OperatorTools.parseString(stringObj);
        if (string == null) {
            return null;
        }

        try {
            String charset = StandardCharsets.UTF_8.toString();
            if (charsetParser != null) {
                Object charsetObj = charsetParser.parse(sourceData, rowIndex, context);
                if (charsetObj != null) {
                    charset = OperatorTools.parseString(charsetObj);
                }
            }
            return URLEncoder.encode(string, charset);
        } catch (Exception e) {
            return null;
        }
    }

}

